// Financial Tracking & Tax Agent
// Monitors all revenue streams, tracks expenses, and manages tax obligations

const financialConfig = {
  revenue_sources: {
    patreon: {
      enabled: $env.PATREON_ENABLED === 'true',
      apiKey: $env.PATREON_API_KEY,
      campaignId: $env.PATREON_CAMPAIGN_ID,
      taxCategory: 'subscription_income'
    },
    shopify: {
      enabled: $env.SHOPIFY_ENABLED === 'true',
      apiKey: $env.SHOPIFY_API_KEY,
      shopDomain: $env.SHOPIFY_SHOP_DOMAIN,
      accessToken: $env.SHOPIFY_ACCESS_TOKEN,
      taxCategory: 'product_sales'
    },
    printify: {
      enabled: $env.PRINTIFY_ENABLED === 'true',
      apiKey: $env.PRINTIFY_API_KEY,
      shopId: $env.PRINTIFY_SHOP_ID,
      taxCategory: 'product_sales'
    },
    youtube: {
      enabled: $env.YOUTUBE_MONETIZATION_ENABLED === 'true',
      apiKey: $env.YOUTUBE_API_KEY,
      taxCategory: 'advertising_revenue'
    },
    affiliates: {
      enabled: $env.AFFILIATE_TRACKING_ENABLED === 'true',
      networks: {
        amazon: { tag: $env.AMAZON_AFFILIATE_TAG },
        booking: { id: $env.BOOKING_AFFILIATE_ID },
        worldnomads: { id: $env.WORLDNOMADS_AFFILIATE_ID }
      },
      taxCategory: 'affiliate_commissions'
    },
    stripe: {
      enabled: $env.STRIPE_ENABLED === 'true',
      apiKey: $env.STRIPE_API_KEY,
      taxCategory: 'payment_processing'
    },
    paypal: {
      enabled: $env.PAYPAL_ENABLED === 'true',
      clientId: $env.PAYPAL_CLIENT_ID,
      clientSecret: $env.PAYPAL_CLIENT_SECRET,
      taxCategory: 'payment_processing'
    }
  },

  expense_categories: {
    business_operations: {
      subcategories: ['software_subscriptions', 'hosting', 'domain_names', 'api_costs'],
      deductible: true
    },
    content_creation: {
      subcategories: ['equipment', 'editing_software', 'stock_photos', 'music_licensing'],
      deductible: true
    },
    marketing: {
      subcategories: ['advertising', 'influencer_payments', 'promotional_materials'],
      deductible: true
    },
    travel: {
      subcategories: ['flights', 'accommodation', 'meals', 'transportation'],
      deductible: true,
      business_percentage: 0.80 // 80% business use
    },
    professional_services: {
      subcategories: ['accounting', 'legal', 'consulting', 'freelancers'],
      deductible: true
    }
  },

  tax_settings: {
    business_structure: $env.BUSINESS_STRUCTURE || 'sole_proprietorship',
    tax_year: new Date().getFullYear(),
    quarterly_due_dates: [
      `${new Date().getFullYear()}-04-15`, // Q1
      `${new Date().getFullYear()}-06-15`, // Q2
      `${new Date().getFullYear()}-09-15`, // Q3
      `${new Date().getFullYear() + 1}-01-15`  // Q4
    ],
    estimated_tax_rate: parseFloat($env.ESTIMATED_TAX_RATE || '0.25'), // 25% default
    self_employment_tax_rate: 0.1413, // 14.13% for 2024
    standard_deduction: 14600, // 2024 standard deduction for single filers
    quarterly_threshold: 1000 // Minimum quarterly payment threshold
  },

  tracking_periods: {
    daily: new Date().toISOString().split('T')[0],
    weekly: getWeekRange(),
    monthly: getMonthRange(),
    quarterly: getQuarterRange(),
    yearly: getYearRange()
  }
};

// Helper functions for date ranges
function getWeekRange() {
  const now = new Date();
  const startOfWeek = new Date(now.setDate(now.getDate() - now.getDay()));
  const endOfWeek = new Date(now.setDate(startOfWeek.getDate() + 6));
  return {
    start: startOfWeek.toISOString().split('T')[0],
    end: endOfWeek.toISOString().split('T')[0]
  };
}

function getMonthRange() {
  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);
  return {
    start: startOfMonth.toISOString().split('T')[0],
    end: endOfMonth.toISOString().split('T')[0]
  };
}

function getQuarterRange() {
  const now = new Date();
  const quarter = Math.floor(now.getMonth() / 3);
  const startOfQuarter = new Date(now.getFullYear(), quarter * 3, 1);
  const endOfQuarter = new Date(now.getFullYear(), quarter * 3 + 3, 0);
  return {
    start: startOfQuarter.toISOString().split('T')[0],
    end: endOfQuarter.toISOString().split('T')[0]
  };
}

function getYearRange() {
  const now = new Date();
  const startOfYear = new Date(now.getFullYear(), 0, 1);
  const endOfYear = new Date(now.getFullYear(), 11, 31);
  return {
    start: startOfYear.toISOString().split('T')[0],
    end: endOfYear.toISOString().split('T')[0]
  };
}

return {
  financialConfig,
  analysisTimestamp: new Date().toISOString(),
  enabledSources: Object.keys(financialConfig.revenue_sources).filter(
    source => financialConfig.revenue_sources[source].enabled
  )
};

// Configure revenue source data collection
const financialData = $('Prepare Financial Analysis').first();
const currentSource = financialData.enabledSources[$('Process Each Revenue Source').itemIndex];

if (!currentSource) {
  return null;
}

const sourceConfig = financialData.financialConfig.revenue_sources[currentSource];
const trackingPeriods = financialData.financialConfig.tracking_periods;

// Revenue source API configurations
function getPatreonFinancialConfig(config, periods) {
  return {
    source: 'patreon',
    apiUrl: `https://www.patreon.com/api/oauth2/v2/campaigns/${config.campaignId}/pledges`,
    headers: { 'Authorization': `Bearer ${config.apiKey}` },
    params: {
      'include': 'patron,reward',
      'page[count]': 1000
    },
    taxCategory: config.taxCategory,
    revenueType: 'recurring'
  };
}

function getShopifyFinancialConfig(config, periods) {
  return {
    source: 'shopify',
    apiUrl: `https://${config.shopDomain}.myshopify.com/admin/api/2023-10/orders.json`,
    headers: { 'X-Shopify-Access-Token': config.accessToken },
    params: {
      'created_at_min': periods.monthly.start + 'T00:00:00Z',
      'created_at_max': periods.monthly.end + 'T23:59:59Z',
      'financial_status': 'paid',
      'limit': 250
    },
    taxCategory: config.taxCategory,
    revenueType: 'one_time'
  };
}

function getStripeFinancialConfig(config, periods) {
  return {
    source: 'stripe',
    apiUrl: 'https://api.stripe.com/v1/charges',
    headers: { 'Authorization': `Bearer ${config.apiKey}` },
    params: {
      'created[gte]': Math.floor(new Date(periods.monthly.start).getTime() / 1000),
      'created[lte]': Math.floor(new Date(periods.monthly.end).getTime() / 1000),
      'limit': 100
    },
    taxCategory: config.taxCategory,
    revenueType: 'payment_processing'
  };
}

function getPayPalFinancialConfig(config, periods) {
  return {
    source: 'paypal',
    apiUrl: 'https://api.paypal.com/v1/reporting/transactions',
    headers: { 
      'Authorization': `Bearer ${config.accessToken}`,
      'Content-Type': 'application/json'
    },
    params: {
      'start_date': periods.monthly.start + 'T00:00:00Z',
      'end_date': periods.monthly.end + 'T23:59:59Z',
      'fields': 'all',
      'page_size': 500
    },
    taxCategory: config.taxCategory,
    revenueType: 'payment_processing'
  };
}

// Get configuration for current source
let apiConfig;
switch (currentSource) {
  case 'patreon':
    apiConfig = getPatreonFinancialConfig(sourceConfig, trackingPeriods);
    break;
  case 'shopify':
    apiConfig = getShopifyFinancialConfig(sourceConfig, trackingPeriods);
    break;
  case 'stripe':
    apiConfig = getStripeFinancialConfig(sourceConfig, trackingPeriods);
    break;
  case 'paypal':
    apiConfig = getPayPalFinancialConfig(sourceConfig, trackingPeriods);
    break;
  default:
    // For sources without direct API access, return manual tracking config
    apiConfig = {
      source: currentSource,
      manual_tracking: true,
      taxCategory: sourceConfig.taxCategory,
      revenueType: 'manual_entry'
    };
}

return {
  ...apiConfig,
  trackingPeriods,
  taxSettings: financialData.financialConfig.tax_settings,
  analysisTimestamp: financialData.analysisTimestamp
};

// Process revenue data and calculate financial metrics
const apiResponse = $input.first();
const sourceConfig = $('Configure Revenue Tracking').first();

// Process different revenue source responses
function processPatreonRevenue(data) {
  const pledges = data.data || [];
  const totalRevenue = pledges.reduce((sum, pledge) => {
    return sum + (pledge.attributes?.amount_cents || 0) / 100;
  }, 0);

  return {
    gross_revenue: totalRevenue,
    transaction_count: pledges.length,
    average_transaction: pledges.length > 0 ? totalRevenue / pledges.length : 0,
    revenue_type: 'subscription',
    processing_fees: totalRevenue * 0.05 // Patreon's 5% fee
  };
}

function processShopifyRevenue(data) {
  const orders = data.orders || [];
  const totalRevenue = orders.reduce((sum, order) => sum + parseFloat(order.total_price || 0), 0);
  const totalTax = orders.reduce((sum, order) => sum + parseFloat(order.total_tax || 0), 0);
  const shippingCosts = orders.reduce((sum, order) => {
    return sum + order.shipping_lines?.reduce((shipSum, line) => shipSum + parseFloat(line.price || 0), 0) || 0;
  }, 0);

  return {
    gross_revenue: totalRevenue,
    net_revenue: totalRevenue - totalTax,
    transaction_count: orders.length,
    average_transaction: orders.length > 0 ? totalRevenue / orders.length : 0,
    revenue_type: 'product_sales',
    taxes_collected: totalTax,
    shipping_revenue: shippingCosts,
    processing_fees: totalRevenue * 0.029 // Shopify Payments fee
  };
}

function processStripeRevenue(data) {
  const charges = data.data || [];
  const successfulCharges = charges.filter(charge => charge.status === 'succeeded');
  const totalRevenue = successfulCharges.reduce((sum, charge) => sum + (charge.amount / 100), 0);
  const totalFees = successfulCharges.reduce((sum, charge) => {
    return sum + ((charge.application_fee_amount || 0) / 100);
  }, 0);

  return {
    gross_revenue: totalRevenue,
    net_revenue: totalRevenue - totalFees,
    transaction_count: successfulCharges.length,
    average_transaction: successfulCharges.length > 0 ? totalRevenue / successfulCharges.length : 0,
    revenue_type: 'payment_processing',
    processing_fees: totalFees
  };
}

function processPayPalRevenue(data) {
  const transactions = data.transaction_details || [];
  const revenue_transactions = transactions.filter(t => 
    t.transaction_info?.transaction_status === 'S' && 
    parseFloat(t.transaction_info?.transaction_amount?.value || 0) > 0
  );

  const totalRevenue = revenue_transactions.reduce((sum, transaction) => {
    return sum + parseFloat(transaction.transaction_info?.transaction_amount?.value || 0);
  }, 0);

  const totalFees = revenue_transactions.reduce((sum, transaction) => {
    return sum + Math.abs(parseFloat(transaction.transaction_info?.fee_amount?.value || 0));
  }, 0);

  return {
    gross_revenue: totalRevenue,
    net_revenue: totalRevenue - totalFees,
    transaction_count: revenue_transactions.length,
    average_transaction: revenue_transactions.length > 0 ? totalRevenue / revenue_transactions.length : 0,
    revenue_type: 'payment_processing',
    processing_fees: totalFees
  };
}

// Process data based on source type
let revenueData;
switch (sourceConfig.source) {
  case 'patreon':
    revenueData = processPatreonRevenue(apiResponse);
    break;
  case 'shopify':
    revenueData = processShopifyRevenue(apiResponse);
    break;
  case 'stripe':
    revenueData = processStripeRevenue(apiResponse);
    break;
  case 'paypal':
    revenueData = processPayPalRevenue(apiResponse);
    break;
  default:
    revenueData = { gross_revenue: 0, net_revenue: 0, transaction_count: 0 };
}

// Calculate tax implications
const taxSettings = sourceConfig.taxSettings;
const grossRevenue = revenueData.gross_revenue || 0;
const netRevenue = revenueData.net_revenue || grossRevenue;

// Estimate taxes owed
const estimatedIncomeTax = netRevenue * taxSettings.estimated_tax_rate;
const estimatedSelfEmploymentTax = netRevenue * taxSettings.self_employment_tax_rate;
const totalEstimatedTax = estimatedIncomeTax + estimatedSelfEmploymentTax;

// Calculate quarterly payment recommendation
const quarterlyPayment = totalEstimatedTax / 4;
const shouldMakeQuarterlyPayment = quarterlyPayment >= taxSettings.quarterly_threshold;

return {
  source: sourceConfig.source,
  tax_category: sourceConfig.taxCategory,
  revenue_data: revenueData,
  tax_calculations: {
    gross_revenue: grossRevenue,
    net_revenue: netRevenue,
    estimated_income_tax: estimatedIncomeTax,
    estimated_self_employment_tax: estimatedSelfEmploymentTax,
    total_estimated_tax: totalEstimatedTax,
    quarterly_payment: quarterlyPayment,
    should_make_quarterly_payment: shouldMakeQuarterlyPayment
  },
  tracking_period: sourceConfig.trackingPeriods.monthly,
  analysis_timestamp: sourceConfig.analysisTimestamp
};

// Compile comprehensive financial report
const allRevenueData = $input.all();
const financialData = $('Prepare Financial Analysis').first();

// Aggregate revenue by source and tax category
const revenueBySource = {};
const revenueByTaxCategory = {};
let totalGrossRevenue = 0;
let totalNetRevenue = 0;
let totalEstimatedTax = 0;
let totalQuarterlyPayment = 0;

allRevenueData.forEach(sourceData => {
  if (sourceData.revenue_data) {
    const source = sourceData.source;
    const taxCategory = sourceData.tax_category;
    const revenueData = sourceData.revenue_data;
    const taxCalcs = sourceData.tax_calculations;

    // Aggregate by source
    revenueBySource[source] = {
      gross_revenue: revenueData.gross_revenue || 0,
      net_revenue: revenueData.net_revenue || revenueData.gross_revenue || 0,
      transaction_count: revenueData.transaction_count || 0,
      processing_fees: revenueData.processing_fees || 0,
      estimated_tax: taxCalcs?.total_estimated_tax || 0
    };

    // Aggregate by tax category
    if (!revenueByTaxCategory[taxCategory]) {
      revenueByTaxCategory[taxCategory] = {
        gross_revenue: 0,
        net_revenue: 0,
        estimated_tax: 0
      };
    }

    revenueByTaxCategory[taxCategory].gross_revenue += revenueData.gross_revenue || 0;
    revenueByTaxCategory[taxCategory].net_revenue += revenueData.net_revenue || revenueData.gross_revenue || 0;
    revenueByTaxCategory[taxCategory].estimated_tax += taxCalcs?.total_estimated_tax || 0;

    // Overall totals
    totalGrossRevenue += revenueData.gross_revenue || 0;
    totalNetRevenue += revenueData.net_revenue || revenueData.gross_revenue || 0;
    totalEstimatedTax += taxCalcs?.total_estimated_tax || 0;
    totalQuarterlyPayment += taxCalcs?.quarterly_payment || 0;
  }
});

// Calculate financial health metrics
const profitMargin = totalGrossRevenue > 0 ? (totalNetRevenue / totalGrossRevenue) * 100 : 0;
const effectiveTaxRate = totalNetRevenue > 0 ? (totalEstimatedTax / totalNetRevenue) * 100 : 0;
const cashFlowAfterTax = totalNetRevenue - totalEstimatedTax;

// Check quarterly payment requirements
const taxSettings = financialData.financialConfig.tax_settings;
const nextQuarterlyDue = getNextQuarterlyDueDate(taxSettings.quarterly_due_dates);
const daysUntilDue = Math.ceil((new Date(nextQuarterlyDue) - new Date()) / (1000 * 60 * 60 * 24));
const quarterlyPaymentRequired = totalQuarterlyPayment >= taxSettings.quarterly_threshold;

// Generate financial insights and recommendations
const insights = [];
const recommendations = [];

// Revenue insights
if (totalGrossRevenue > 0) {
  insights.push(`Generated $${totalGrossRevenue.toFixed(2)} in gross revenue this month`);

  if (profitMargin > 70) {
    insights.push('Excellent profit margins - consider scaling operations');
  } else if (profitMargin < 30) {
    insights.push('Low profit margins - review expenses and pricing');
    recommendations.push('Analyze cost structure and optimize pricing strategy');
  }
}

// Tax insights
if (quarterlyPaymentRequired) {
  insights.push(`Quarterly tax payment of $${totalQuarterlyPayment.toFixed(2)} recommended`);
  if (daysUntilDue <= 30) {
    recommendations.push(`URGENT: Quarterly tax payment due in ${daysUntilDue} days`);
  }
}

// Cash flow insights
if (cashFlowAfterTax < 0) {
  recommendations.push('Negative cash flow after taxes - consider tax planning strategies');
} else if (cashFlowAfterTax > totalNetRevenue * 0.8) {
  recommendations.push('Strong cash position - consider business investments or tax-advantaged savings');
}

// Top performing revenue source
const topRevenueSource = Object.keys(revenueBySource).reduce((a, b) => 
  revenueBySource[a].gross_revenue > revenueBySource[b].gross_revenue ? a : b
);

function getNextQuarterlyDueDate(dueDates) {
  const now = new Date();
  return dueDates.find(date => new Date(date) > now) || dueDates[0];
}

// Create comprehensive financial summary
const financialSummary = {
  overview: {
    total_gross_revenue: totalGrossRevenue,
    total_net_revenue: totalNetRevenue,
    total_estimated_tax: totalEstimatedTax,
    cash_flow_after_tax: cashFlowAfterTax,
    profit_margin: profitMargin,
    effective_tax_rate: effectiveTaxRate,
    top_revenue_source: topRevenueSource
  },
  revenue_by_source: revenueBySource,
  revenue_by_tax_category: revenueByTaxCategory,
  tax_obligations: {
    quarterly_payment_due: totalQuarterlyPayment,
    payment_required: quarterlyPaymentRequired,
    next_due_date: nextQuarterlyDue,
    days_until_due: daysUntilDue
  },
  insights,
  recommendations: recommendations.slice(0, 5),
  analysis_timestamp: financialData.analysisTimestamp,
  tracking_period: financialData.financialConfig.tracking_periods.monthly
};

return financialSummary;

