• Gross Revenue: ${{ $json.overview.total_gross_revenue.toFixed(2) }}
• Net Revenue: ${{ $json.overview.total_net_revenue.toFixed(2) }}
• Profit Margin: {{ $json.overview.profit_margin.toFixed(1) }}%
• Top Source: {{ $json.overview.top_revenue_source.toUpperCase() }}

*Tax Obligations:*
• Estimated Tax: ${{ $json.overview.total_estimated_tax.toFixed(2) }}
• Quarterly Payment: ${{ $json.tax_obligations.quarterly_payment_due.toFixed(2) }}
• Next Due: {{ $json.tax_obligations.next_due_date }} ({{ $json.tax_obligations.days_until_due }} days)
• Payment Required: {{ $json.tax_obligations.payment_required ? 'YES' : 'NO' }}

*Cash Flow:*
• After Tax: ${{ $json.overview.cash_flow_after_tax.toFixed(2) }}
• Tax Rate: {{ $json.overview.effective_tax_rate.toFixed(1) }}%

*Key Insights:*
{{ $json.insights.slice(0, 3).map(insight => `• ${insight}`).join('
') }}

*Recommendations:*
{{ $json.recommendations.slice(0, 3).map((rec, i) => `${i+1}. ${rec}`).join('
') }}

